// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
// STRY0076609 removed the condition to stop when loading.  Even set when loading
if(newValue == 'true'){
	g_form.showFieldMsg('u_wait_for_subtasks_to_finish', 'This Task is dependent on the completion of its Subtasks and it will not be marked as Unassigned or Assigned until all Subtasks have been Completed, Canceled, or Closed Incomplete.','info');
} else if (!isLoading && newValue == 'false'){
	g_form.showFieldMsg('u_wait_for_subtasks_to_finish', 'This Task is no longer dependent on the completion of its Subtasks.','info');
}

}
